
import Link from 'next/link';
import { Plus, Edit, Trash2, Calendar, BookOpen } from 'lucide-react';
import { getTodasAulas } from '@/src/lib/supabase/queries/aulas';
import { Aula } from '@/types/aulas';

export default async function AdminAulasPage() {
  const aulas = await getTodasAulas();

  return (
    <div className="p-6 lg:p-8 space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Gestão de Aulas</h1>
          <p className="text-gray-600 mt-1">Gerencie o conteúdo do Método Alpha</p>
        </div>
        <Link
          href="/admin/aulas/nova"
          className="inline-flex items-center gap-2 bg-red-600 hover:bg-red-700 text-white px-4 py-2.5 rounded-lg font-medium transition-colors shadow-sm"
        >
          <Plus className="w-5 h-5" />
          Nova Aula
        </Link>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-600">
            <thead className="bg-gray-50 text-gray-900 font-semibold border-b border-gray-200">
              <tr>
                <th className="px-6 py-4 w-20">#</th>
                <th className="px-6 py-4">Título</th>
                <th className="px-6 py-4">Data</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {aulas.length > 0 ? (
                aulas.map((aula) => (
                  <tr key={aula.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-gray-900">
                      {aula.numero}
                    </td>
                    <td className="px-6 py-4">
                      <div className="font-medium text-gray-900">{aula.titulo}</div>
                      <div className="text-xs text-gray-500 line-clamp-1">
                        {aula.objetivo_didatico}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <Calendar className="w-4 h-4 text-gray-400" />
                        {new Date(aula.data_programada).toLocaleDateString('pt-BR')}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border
                        ${aula.status === 'agendada' ? 'bg-blue-50 text-blue-700 border-blue-100' : ''}
                        ${aula.status === 'concluida' ? 'bg-green-50 text-green-700 border-green-100' : ''}
                        ${aula.status === 'rascunho' ? 'bg-gray-100 text-gray-700 border-gray-200' : ''}
                      `}>
                        {aula.status || 'Rascunho'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <Link
                          href={`/admin/aulas/${aula.id}`}
                          className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                          title="Editar"
                        >
                          <Edit className="w-4 h-4" />
                        </Link>
                        {/* Botão de delete seria idealmente um form action ou componente client side */}
                        <button className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center">
                    <div className="flex flex-col items-center justify-center">
                      <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mb-3">
                        <BookOpen className="w-6 h-6 text-gray-400" />
                      </div>
                      <p className="text-gray-900 font-medium">Nenhuma aula encontrada</p>
                      <p className="text-gray-500 text-sm mt-1">
                        Comece criando a primeira aula do curso.
                      </p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
